package com.lightevents.invoices;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant;
@Entity @Table(name="invoices")
public class Invoice { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(unique=true) private String invoiceNumber; private String reservationReference; private Long eventId; private String buyerName; private String buyerEmail; private String buyerPhone; private String buyerWhatsapp; private boolean companyPurchase; private String companyName; private BigDecimal grossAmount; private BigDecimal platformFee; private BigDecimal organizerNet; private String currency; @Lob @Column(length=100000) private String pdfBase64; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getInvoiceNumber(){return invoiceNumber;} public void setInvoiceNumber(String v){invoiceNumber=v;} public String getReservationReference(){return reservationReference;} public void setReservationReference(String v){reservationReference=v;} public Long getEventId(){return eventId;} public void setEventId(Long v){eventId=v;} public String getBuyerName(){return buyerName;} public void setBuyerName(String v){buyerName=v;} public String getBuyerEmail(){return buyerEmail;} public void setBuyerEmail(String v){buyerEmail=v;} public String getBuyerPhone(){return buyerPhone;} public void setBuyerPhone(String v){buyerPhone=v;} public String getBuyerWhatsapp(){return buyerWhatsapp;} public void setBuyerWhatsapp(String v){buyerWhatsapp=v;} public boolean isCompanyPurchase(){return companyPurchase;} public void setCompanyPurchase(boolean v){companyPurchase=v;} public String getCompanyName(){return companyName;} public void setCompanyName(String v){companyName=v;} public BigDecimal getGrossAmount(){return grossAmount;} public void setGrossAmount(BigDecimal v){grossAmount=v;} public BigDecimal getPlatformFee(){return platformFee;} public void setPlatformFee(BigDecimal v){platformFee=v;} public BigDecimal getOrganizerNet(){return organizerNet;} public void setOrganizerNet(BigDecimal v){organizerNet=v;} public String getCurrency(){return currency;} public void setCurrency(String v){currency=v;} public String getPdfBase64(){return pdfBase64;} public void setPdfBase64(String v){pdfBase64=v;} public Instant getCreatedAt(){return createdAt;} }
